    if (av_dict_set(&dict, e->key, "new val OK", 0) < 0)
        return 1;
    e = av_dict_get(dict, "key", NULL, 0);
    printf("%s\n", e->value);
    if (av_dict_set(&dict, e->key, e->value, 0) < 0)
        return 1;
    e = av_dict_get(dict, "key", NULL, 0);
    printf("%s\n", e->value);
    av_dict_free(&dict);

    return 0;
}

